  (5, 'מדעים ומחקר', 'ביולוגיה, כימיה, פיזיקה, מדעי החברה', 44, 'אני מחזק את יכולת ההתמדה והדיוק במחקר.'),
  (5, 'מדעים ומחקר', 'ביולוגיה, כימיה, פיזיקה, מדעי החברה', 45, 'אני מסייע לזהות מגמות ושינויים במערכות טבעיות וחברתיות.'),
  (5, 'מדעים ומחקר', 'ביולוגיה, כימיה, פיזיקה, מדעי החברה', 46, 'אני מפתח מיומנויות ניתוח מידע רב-ממדי.'),
  (5, 'מדעים ומחקר', 'ביולוגיה, כימיה, פיזיקה, מדעי החברה', 47, 'אני מסייע בקידום ידע מדעי חדשני.'),
  (5, 'מדעים ומחקר', 'ביולוגיה, כימיה, פיזיקה, מדעי החברה', 48, 'אני מחזק את תחושת האחריות והאתיקה במחקר.'),
  (5, 'מדעים ומחקר', 'ביולוגיה, כימיה, פיזיקה, מדעי החברה', 49, 'אני מסייע ביצירת חיבור בין מדע, חברה וטכנולוגיה.'),
  (5, 'מדעים ומחקר', 'ביולוגיה, כימיה, פיזיקה, מדעי החברה', 50, 'אני משפיע על ההבנה שלנו את העולם והחברה דרך מחקר וידע.')
